import React, {useEffect, useRef, useState} from 'react'
import { motion } from 'framer-motion'
import { useStore } from '../store'
import Picker from '@emoji-mart/react'
import io from 'socket.io-client'

const socket = io('http://localhost:8000/ws')

export default function ChatWindow({chat}){
  const {focusChat, openChat} = useStore()
  const ref = useRef()
  const [messages, setMessages] = useState([])
  const [text, setText] = useState('')
  const [showEmoji, setShowEmoji] = useState(false)
  const [shaking, setShaking] = useState(false)

  useEffect(()=>{
    socket.on('message', m => setMessages(prev=>[...prev,m]))
    socket.on('buzz', data => {
      setShaking(true)
      const audio = new Audio('/buzz.mp3')
      audio.play().catch(()=>{})
      setTimeout(()=>setShaking(false), 1200)
    })
    return ()=>{ socket.off('message'); socket.off('buzz') }
  },[])

  function handleFocus(){
    focusChat(chat.id)
  }

  function sendMessage(){
    socket.emit('send_message', {sender_id: 1, receiver_id: chat.id, content: text, content_type: 'text'})
    setText('')
  }

  function sendBuzz(){
    socket.emit('send_buzz', {sender_id:1, receiver_id: chat.id}, (res)=>{
      if(res && res.status==='error'){
        // show cooldown UI
      }
    })
  }

  function onEmojiSelect(emoji){
    setText(prev => prev + emoji.native)
    setShowEmoji(false)
  }

  async function handleFile(e){
    const f = e.target.files[0]
    if(!f) return
    // upload to storage (stub) -> get URL
    const url = URL.createObjectURL(f)
    socket.emit('send_message', {sender_id:1, receiver_id: chat.id, content: f.name, content_type: 'media', media_url: url})
  }

  return (
    <motion.div
      className={`fixed bottom-4 right-4 w-80 bg-white rounded shadow-lg flex flex-col ${shaking? 'animate-shake':''}`}
      style={{zIndex: chat.zIndex}}
      onMouseDown={handleFocus}
      ref={ref}
      initial={{opacity:0, y:20}}
      animate={{opacity:1, y:0}}
    >
      <div className="p-2 bg-blue-600 text-white rounded-t flex justify-between">
        <div>{chat.user}</div>
        <div className="flex gap-2">
          <button onClick={sendBuzz} title="Buzz">🔊</button>
          <button onClick={()=>setShowEmoji(s=>!s)}>😊</button>
          <input type="file" onChange={handleFile} className="hidden" id={`file-${chat.id}`} />
          <label htmlFor={`file-${chat.id}`} className="cursor-pointer">📎</label>
        </div>
      </div>
      <div className="p-2 flex-1 overflow-y-auto h-48">
        {messages.map((m,i)=>(<div key={i} className="mb-2">{m.content}</div>))}
      </div>
      <div className="p-2 border-t flex items-center gap-2">
        <input className="flex-1 p-1 border rounded" value={text} onChange={e=>setText(e.target.value)} />
        <button onClick={sendMessage} className="bg-blue-500 text-white px-3 py-1 rounded">Send</button>
      </div>
      {showEmoji && <div className="p-1"><Picker onEmojiSelect={onEmojiSelect} /></div>}
    </motion.div>
  )
}
